code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            int n = sc.nextInt();
            int sum = 0;
            for (int i = 0; i < n; i++) {
                int x = sc.nextInt();
                if (x < 0) sum += -x;
            }
            System.out.println(sum + 1);
        }
    }
}

code.JavaScript:
const readline = require('readline').createInterface({ input: process.stdin, output: process.stdout });
let i = 0;
let t;
let input = [];
readline.on('line', line => {
    if (i === 0) t = parseInt(line);
    else input.push(line);
    i++;
    if (i === t * 2 + 1) {
        for (let j = 0; j < t; j++) {
            let n = parseInt(input[j * 2]);
            let sum = 0;
            let arr = input[j * 2 + 1].split(' ').map(x => parseInt(x));
            for (let k = 0; k < n; k++) {
                if (arr[k] < 0) sum += -arr[k];
            }
            console.log(sum + 1);
        }
    }
});
